command:
printf '# TS Style

## Prefer const
Use const not var in .ts TypeScript interface code.
' > ts.md && bash "$CLAUDE_PLUGIN_ROOT/commands/extract-rules-from-url.sh" --source ts.md --source-id ts-style --json > rules.json 2>/dev/null && node -e 'const r=require(process.cwd()+"/rules.json");if(!(Array.isArray(r)?r:r.rules||[]).length)process.exit(1)' && bash "$CLAUDE_PLUGIN_ROOT/commands/classify-rule.sh" --title 'Prefer const' --prose 'Use const not var in .ts TypeScript interface code.' --json > c.json 2>/dev/null && bash "$CLAUDE_PLUGIN_ROOT/commands/route-rule.sh" --in c.json --json > r.json 2>/dev/null && node -e 'const c=require(process.cwd()+"/c.json"),r=require(process.cwd()+"/r.json");if(!c.applies_to.linguist_aliases.includes("typescript"))process.exit(1);if(!r.enforced_by.some(x=>x.tool==="eslint"))process.exit(1)' && mkdir -p app && printf 'const x = 1;
export default x;
' > app/index.ts && bash "$CLAUDE_PLUGIN_ROOT/rubric/composite-audit.sh" --root app 2>a.txt; ae=$?; [ "$ae" -eq 0 ] && grep -q 'status=green' a.txt && echo pipeline-code-url-to-audit 1>&2
